  SELECT sd.id, sd.time, sd.value,
         COALESCE(a.type, 'No Alert') AS alert_type,
         COALESCE(a.pulses, 0) AS pulses,
         COALESCE(a.intensity, 0) AS intensity,
         COALESCE(a.duration, 0) AS duration,
         COALESCE(a.interval, 0) AS interval,
         sd.userid,
         sd.sensorid
  FROM public."SensorData" sd
  LEFT JOIN public."Alert" a ON sd.alertid = a.alertid
`;

